using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class TrainingMetrics
{
    public double MicroAccuracy { get; set; }
    public double MacroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<TicketModelService> _logger;
    private readonly string _modelPath;
    private readonly string _dataPath;

    public TrainingMetrics? LastTrainingMetrics { get; private set; }
    public VBuffer<ReadOnlyMemory<char>> CategoryLabels { get; private set; }

    public TicketModelService(ILogger<TicketModelService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "ticket_model.zip");
    }

    public void TrainAndSave()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text
                .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        LastTrainingMetrics = new TrainingMetrics
        {
            MicroAccuracy = metrics.MicroAccuracy,
            MacroAccuracy = metrics.MacroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction
        };

        _logger.LogInformation(
            "Model evaluation — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

        // Extract the label names from the trained pipeline for confidence mapping
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        model.LastTransformer.Model.GetLabelInfo(out labelBuffer);
        CategoryLabels = labelBuffer;

        _mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }

    public string ModelPath => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _pool;
    private readonly TicketModelService _modelService;

    public TicketController(
        PredictionEnginePool<TicketInput, TicketPrediction> pool,
        TicketModelService modelService)
    {
        _pool = pool;
        _modelService = modelService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _pool.Predict(input);

        var labels = _modelService.CategoryLabels;
        var confidence = new Dictionary<string, float>();
        var values = labels.GetValues();
        for (int i = 0; i < values.Length; i++)
        {
            confidence[values[i].ToString()] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    [HttpGet("metrics")]
    public ActionResult<TrainingMetrics> GetMetrics()
    {
        if (_modelService.LastTrainingMetrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(_modelService.LastTrainingMetrics);
    }
}

