using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model at startup
var modelService = new TicketModelService(
    builder.Services.BuildServiceProvider().GetRequiredService<ILogger<TicketModelService>>(),
    builder.Environment);
modelService.TrainAndSave();
builder.Services.AddSingleton(modelService);

// Thread-safe prediction engine pool
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelService.ModelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

